    public static int sum_positive(List<Integer> numbers) {
        List<Integer> positiveNumbers = new ArrayList<>();
        for (int number : numbers) {
            if (number > 0) {
                positiveNumbers.add(number);
            }
        }
        int sum = 0;
        for (int positiveNumber : positiveNumbers) {
            sum += positiveNumber;
        }
        return sum;
    }

    public static void main(String[] args) {
        List<Integer> input = List.of(1, -2, 3, -4, 5);
        int result = sum_positive(input);
        System.out.println(result); // Output: 9
    }
}

public class SafeDivide {

    public static Result<Integer, String> safeDivide(int numerator, int denominator) {
        if (denominator == 0) {
            return Result.err("division by zero");
        }
        return Result.ok(numerator / denominator);
    }

    public static class Result<T, E> {
        private final T value;
        private final E error;
        private final boolean isError;

        private Result(T value, E error, boolean isError) {
            this.value = value;
            this.error = error;
            this.isError = isError;
        }

        public static <T, E> Result<T, E> ok(T value) {
            return new Result<>(value, null, false);
        }

        public static <T, E> Result<T, E> err(E error) {
            return new Result<>(null, error, true);
        }

        public boolean isError() {
            return isError;
        }

        public T getValue() {
            if (isError) {
                throw new IllegalStateException("No value present");
            }
            return value;
        }

        public E getError() {
            if (!isError) {
                throw new IllegalStateException("No error present");
            }
            return error;
        }
    }
}

import java.io.BufferedWriter;
import java.io.FileWriter;
import java.io.IOException;

public class FileIO {

    public static Result writeGreeting(String filename) {
        BufferedWriter writer = null;
        try {
            writer = new BufferedWriter(new FileWriter(filename));
            writer.write("Hello from the program!");
            return Result.success();
        } catch (IOException e) {
            return Result.error(e.getMessage());
        } finally {
            if (writer != null) {
                try {
                    writer.close();
                } catch (IOException e) {
                    return Result.error(e.getMessage());
                }
            }
        }
    }

    public static class Result {
        private final boolean success;
        private final String errorMessage;

        private Result(boolean success, String errorMessage) {
            this.success = success;
            this.errorMessage = errorMessage;
        }

        public static Result success() {
            return new Result(true, null);
        }

        public static Result error(String errorMessage) {
            return new Result(false, errorMessage);
        }

        public boolean isSuccess() {
            return success;
        }

        public String getErrorMessage() {
            return errorMessage;
        }
    }
}

import java.util.List;

class Point {
    private int x;
    private int y;

    public Point(int x, int y) {
        this.x = x;
        this.y = y;
    }

    public int squaredMag() {
        return x * x + y * y;
    }
}

public class PointOperations {
    public static int filterAndSum(List<Point> points, int maxMag) {
        int total = 0;
        for (Point point : points) {
            if (point.squaredMag() <= maxMag) {
                total += point.squaredMag();
            }
        }
        return total;
    }
}

import java.util.*;

public class WordFrequencyCounter {

    public static Map<String, Integer> countWords(String text) {
        Map<String, Integer> wordCount = new HashMap<>();
        String[] words = text.toLowerCase().split("\\s+");

        for (String word : words) {
            wordCount.put(word, wordCount.getOrDefault(word, 0) + 1);
        }

        return wordCount;
    }

    public static void printTop(Map<String, Integer> wordCount, int n) {
        List<Map.Entry<String, Integer>> sortedEntries = new ArrayList<>(wordCount.entrySet());

        sortedEntries.sort((a, b) -> {
            int countComparison = b.getValue().compareTo(a.getValue());
            if (countComparison != 0) {
                return countComparison;
            }
            return a.getKey().compareTo(b.getKey());
        });

        for (int i = 0; i < Math.min(n, sortedEntries.size()); i++) {
            Map.Entry<String, Integer> entry = sortedEntries.get(i);
            System.out.printf("  %d %s%n", entry.getValue(), entry.getKey());
        }
    }

    public static void main(String[] args) {
        String text = "the cat sat on the mat the cat sat";
        Map<String, Integer> wordCount = countWords(text);
        printTop(wordCount, 5);
    }
}

